// ==================== Stripe Payment Handlers ====================

async function handleCreateCheckoutSession(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const {
    lineItems,
    mode = 'payment',
    successUrl,
    cancelUrl,
    customerEmail,
    customerId,
    metadata,
    allowPromotionCodes,
  } = body.data;

  const validationErrors = [];
  if (!lineItems || !Array.isArray(lineItems) || lineItems.length === 0) {
    validationErrors.push('lineItems is required and must be a non-empty array');
  }
  if (!successUrl) validationErrors.push('successUrl is required');
  if (!cancelUrl) validationErrors.push('cancelUrl is required');
  if (!['payment', 'subscription', 'setup'].includes(mode)) {
    validationErrors.push('mode must be payment, subscription, or setup');
  }

  if (validationErrors.length > 0) {
    return jsonResponse(400, { error: 'Validation failed', details: validationErrors }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('mode', mode);
  params.append('success_url', successUrl);
  params.append('cancel_url', cancelUrl);

  lineItems.forEach((item, index) => {
    if (item.priceId) {
      params.append(`line_items[${index}][price]`, item.priceId);
    } else {
      params.append(`line_items[${index}][price_data][currency]`, item.currency || 'usd');
      params.append(`line_items[${index}][price_data][product_data][name]`, item.name);
      if (item.description) {
        params.append(`line_items[${index}][price_data][product_data][description]`, item.description);
      }
      params.append(`line_items[${index}][price_data][unit_amount]`, String(item.amount));
      if (mode === 'subscription') {
        params.append(`line_items[${index}][price_data][recurring][interval]`, item.interval || 'month');
      }
    }
    params.append(`line_items[${index}][quantity]`, String(item.quantity || 1));
  });

  if (customerEmail) params.append('customer_email', customerEmail);
  if (customerId) params.append('customer', customerId);
  if (allowPromotionCodes) params.append('allow_promotion_codes', 'true');

  if (metadata) {
    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, String(value));
    });
  }

  const result = await stripeRequest('/v1/checkout/sessions', 'POST', params, env);

  if (result.ok) {
    return jsonResponse(200, {
      success: true,
      sessionId: result.data.id,
      url: result.data.url,
    }, corsHeaders);
  }

  return jsonResponse(result.status, {
    error: 'Failed to create checkout session',
    details: result.data?.error?.message || result.data,
  }, corsHeaders);
}

async function handleCreatePaymentIntent(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const {
    amount,
    currency = 'usd',
    customerId,
    description,
    metadata,
    automaticPaymentMethods = true,
    receiptEmail,
  } = body.data;

  const validationErrors = [];
  if (!amount || typeof amount !== 'number' || amount <= 0) {
    validationErrors.push('amount is required and must be a positive number (in cents)');
  }

  if (validationErrors.length > 0) {
    return jsonResponse(400, { error: 'Validation failed', details: validationErrors }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('amount', String(Math.round(amount)));
  params.append('currency', currency);

  if (customerId) params.append('customer', customerId);
  if (description) params.append('description', description);
  if (receiptEmail) params.append('receipt_email', receiptEmail);

  if (automaticPaymentMethods) {
    params.append('automatic_payment_methods[enabled]', 'true');
  }

  if (metadata) {
    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, String(value));
    });
  }

  const result = await stripeRequest('/v1/payment_intents', 'POST', params, env);

  if (result.ok) {
    return jsonResponse(200, {
      success: true,
      paymentIntentId: result.data.id,
      clientSecret: result.data.client_secret,
      status: result.data.status,
    }, corsHeaders);
  }

  return jsonResponse(result.status, {
    error: 'Failed to create payment intent',
    details: result.data?.error?.message || result.data,
  }, corsHeaders);
}

async function handleCreateCustomer(request, env, corsHeaders) {
  const body = await parseJsonBody(request);
  if (body.error) {
    return jsonResponse(400, { error: body.error }, corsHeaders);
  }

  const { email, name, phone, metadata, address } = body.data;

  const validationErrors = [];
  if (!email) validationErrors.push('email is required');

  if (validationErrors.length > 0) {
    return jsonResponse(400, { error: 'Validation failed', details: validationErrors }, corsHeaders);
  }

  const params = new URLSearchParams();
  params.append('email', email);
  if (name) params.append('name', name);
  if (phone) params.append('phone', phone);

  if (address) {
    if (address.line1) params.append('address[line1]', address.line1);
    if (address.line2) params.append('address[line2]', address.line2);
    if (address.city) params.append('address[city]', address.city);
    if (address.state) params.append('address[state]', address.state);
    if (address.postalCode) params.append('address[postal_code]', address.postalCode);
    if (address.country) params.append('address[country]', address.country);
  }

  if (metadata) {
    Object.entries(metadata).forEach(([key, value]) => {
      params.append(`metadata[${key}]`, String(value));
    });
  }

  const result = await stripeRequest('/v1/customers', 'POST', params, env);

  if (result.ok) {
    return jsonResponse(200, {
      success: true,
      customerId: result.data.id,
      email: result.data.email,
      name: result.data.name,
    }, corsHeaders);
  }

  return jsonResponse(result.status, {
    error: 'Failed to create customer',
    details: result.data?.error?.message || result.data,
  }, corsHeaders);
}

